import { Routes } from "@angular/router";
import { DisbursmentComponent } from "../../pages/disbursment/disbursment.component";


export const LayoutRoutes: Routes = [
    {
        path: '',
        loadComponent: () => import('./layout.component').then(comp => comp.LayoutComponent),
        children: [
            {
                path: '',
                pathMatch: 'full',
                redirectTo: 'dashboard'
            },
            {
                path: 'dashboard',
                loadComponent: () => import('../../pages/dashboard/dashboard.component').then(dashboardComp => dashboardComp.DashboardComponent),
                data: { breadcrumb: 'Dashboard' },
            },
            {
                path: 'master',
                loadComponent: () => import('../../pages/master/master.component').then(master => master.MasterComponent),
                data: { breadcrumb: 'Repository' },
            },
            {
                path: 'disbursement',
                loadComponent: () => import('../../pages/disbursment/disbursment.component').then(disbursement => disbursement.DisbursmentComponent),
                data: { breadcrumb: 'Disbursement' },
            },
            {
                path: 'master/mastertabs',
                loadChildren: () => import('../../pages/master/master-tabs/master.routes').then(masterTabs => masterTabs.Masterroutes)
            },
            {
                path: 'pda/create',
                loadComponent: () =>
                    import('../../pages/pda/pda.component').then(
                        (m) => m.PdaComponent
                    ),
                data: { breadcrumb: 'PDA' },
            },
            {
                path: 'pda/edit',
                loadComponent: () =>
                    import('../../pages/pda-edit/pda-edit.component').then(
                        (m) => m.PdaEditComponent
                    ),
                data: { breadcrumb: 'PDA Edit' },
            },
            {
                path: 'fda/create',
                loadComponent: () =>
                    import('../../pages/fda/fda.component').then(
                        (m) => m.FdaComponent
                    ),
                data: { breadcrumb: 'FDA' },
            },
            {
                path: 'fda/create/:id',
                loadComponent: () =>
                    import('../../pages/fda/fda.component').then(
                        (m) => m.FdaComponent
                    ),
                data: { breadcrumb: 'FDA' },
            },
            {
                path: 'fda/edit',
                loadComponent: () =>
                    import('../../pages/fda-edit/fda-edit.component').then(
                        (m) => m.FdaEditComponent
                    ),
                data: { breadcrumb: 'FDA Edit' },
            },
            {
                path: 'client-approval-list',
                loadComponent: () =>
                    import('../../pages/client-approval-list/client-approval-list.component').then(
                        (m) => m.ClientApprovalListComponent
                    ),
                data: { breadcrumb: 'Client Approval List' },
            },
            {
                path: 'client-approval-form',
                loadComponent: () =>
                    import('../../components/client-approval-form/client-approval-form.component').then(
                        (m) => m.ClientApprovalFormComponent
                    ),
                data: { breadcrumb: 'Client Approval Form' },
            },
        ]
    }
];